questions.studyNote:
Canonical Java array scan template

int maxValue(int[] nums) {
    int best = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] > best) {
            best = nums[i];
        }
    }

    return best;
}

